/// <summary>
/// Controller class for handling the Unsold Journal Check Post process in the ETGSPAIN model.
/// </summary>
class ETGSPAINUnsoldJournalCheckPostController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// Constructor to initialize the service and set the execution mode to synchronous.
/// </summary>
protected void new()
{
    super(classStr(ETGSPAINUnsoldJournalCheckPostService), methodStr(ETGSPAINUnsoldJournalCheckPostService, process), SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// Constructs an instance of the controller.
/// </summary>
/// <param name="_args">The arguments passed to the controller.</param>
/// <param name="_executionMode">The execution mode (default is synchronous).</param>
/// <returns>Returns an instance of ETGSPAINUnsoldJournalCheckPostController.</returns>
public static ETGSPAINUnsoldJournalCheckPostController construct(Args _args, SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGSPAINUnsoldJournalCheckPostController controller = new ETGSPAINUnsoldJournalCheckPostController();

    controller.parmExecutionMode(_executionMode);
    controller.parmArgs(_args);

    return controller;
}

    /// <summary>
    /// Main entry point for the controller, typically invoked from a menu item.
    /// </summary>
    /// <param name="_args">The arguments passed to the method.</param>
    public static void main(Args _args)
	{
        if (!_args)
        {
            throw error(Error::wrongUseOfFunction(funcName()));
        }

        if (!_args.record())
        {
            throw error(Error::wrongUseOfFunction(funcName()));
        }

        ETGSPAINUnsoldJournalCheckPostController   controller  = ETGSPAINUnsoldJournalCheckPostController::construct(_args);
        ETGSPAINUnsoldJournalCheckPostContract     contract    = controller.getDataContractObject();

        controller.showBatchTab(false);
        controller.parmLoadFromSysLastValue(false);

        ETGSPAINUnsoldJournalTable etgSpainUnsoldJournalTable = _args.record();

        contract.parmETGSPAINUnsoldJournalId(etgSpainUnsoldJournalTable.JournalId);
        contract.parmArgs(_args);

        controller.startOperation();
	}
